    <div class="container">
        <!-- Column 1: #col-todo -->
        <div id="col-todo" class="column">
            <h3>Todo</h3>
            <div class="card-container">
                <span class="count">0</span>
                <div class="card" data-id="todo">
                    <div class="card-title">New Card</div>
                    <button class="card-del" onclick="deleteTodo(this)">Delete</button>
                </div>
            </div>
        </div>

        <!-- Column 2: #col-doing -->
        <div id="col-doing" class="column">
            <h3>Doing</h3>
            <div class="card-container">
                <span class="count">0</span>
                <div class="card" data-id="doing">
                    <div class="card-title">New Card</div>
                    <button class="card-del" onclick="deleteDoing(this)">Delete</button>
                </div>
            </div>
        </div>

        <!-- Column 3: #col-done -->
        <div id="col-done" class="column">
            <h3>Done</h3>
            <div class="card-container">
                <span class="count">0</span>
                <div class="card" data-id="done">
                    <div class="card-title">New Card</div>
                    <button class="card-del" onclick="deleteDone(this)">Delete</button>
                </div>
            </div>
        </div>
    </div>

    <script>
        // Board state persistence
        let boardState = {
            todo: [],
            doing: [],
            done: []
        };

        function updateCounts() {
            const colTodo = document.getElementById('col-todo');
            const colDoing = document.getElementById('col-doing');
            const colDone = document.getElementById('col-done');

            // Update count in each column header
            colTodo.querySelector('.count').textContent = boardState.todo.length;
            colDoing.querySelector('.count').textContent = boardState.doing.length;
            colDone.querySelector('.count').textContent = boardState.done.length;
        }

        function addNewCard(title) {
            // Create new card element with title from localStorage (persistent)
            const card = document.createElement('div');
            card.className = 'card';
            card.innerHTML = `<span class="card-title">${title}</span>`;

            // Delete button for this card
            card.querySelector('.card-del').addEventListener('click', function() {
                deleteBoardState();
                updateCounts();
            });

            // Store title in localStorage for persistence (though board state is stored separately)
            localStorage.setItem('todoTitle', title);
            return card;
        }

        function deleteTodo(card) {
            const col = document.getElementById('col-todo');
            const index = Array.from(col.querySelectorAll('.card')).indexOf(card);

            if (index > -1) {
                boardState.todo.splice(index, 1);
                updateCounts();

                // Remove card from localStorage
                localStorage.removeItem('todoTitle');
            }
        }

        function deleteDoing(card) {
            const col = document.getElementById('col-doing');
            const index = Array.from(col.querySelectorAll('.card')).indexOf(card);

            if (index > -1) {
                boardState.doing.splice(index, 1);
                updateCounts();

                // Remove card from localStorage
                localStorage.removeItem('doingTitle');
            }
        }

        function deleteDone(card) {
            const col = document.getElementById('col-done');
            const index = Array.from(col.querySelectorAll('.card')).indexOf(card);

            if (index > -1) {
                boardState.done.splice(index, 1);
                updateCounts();

                // Remove card from localStorage
                localStorage.removeItem('doneTitle');
            }
        }

        function updateBoard() {
            // Update counts for all columns
            updateCounts();

            // Clear input and button after adding a new card (as per requirement)
            const todoInput = document.getElementById('#new-card-input');
            if (todoInput.value.trim()) {
                todoInput.value = '';
                todoInput.focus();
            }
        }
    </script>
