<body>
    <div class="container">
        <h2>Kanban Board</h2>

        <!-- Column 1: Todo -->
        <div class="board-row" id="col-todo">
            <span class="count">Todo</span>
            <div class="card"></div>
        </div>

        <!-- Column 2: Doing -->
        <div class="board-row" id="col-doing">
            <span class="count">Doing</span>
            <div class="card"></div>
        </div>

        <!-- Column 3: Done -->
        <div class="board-row" id="col-done">
            <span class="count">Done</span>
            <div class="card"></div>
        </div>
    </div>

    <script>
        // State management
        let boardState = {
            cards: [
                { text: "", title: "Card 1", id: "#new-card-1" },
                { text: "", title: "Card 2", id: "#new-card-2" }
            ],
            columnMap: {
                #col-todo: ["card-1", "card-2"],
                #col-doing: ["card-3", "card-4"],
                #col-done: ["card-5", "card-6"]
            },
            counts: {
                #col-todo: 0,
                #col-doing: 0,
                #col-done: 0
            }
        };

        // Initialize board state from localStorage or reset if not present
        function loadBoardState() {
            const stored = localStorage.getItem('kanban_board_state');
            if (stored) {
                try {
                    const data = JSON.parse(stored);
                    boardState = data;
                    updateCounts();
                } catch (e) {
                    console.error("Invalid JSON from localStorage", e);
                }
            }
        }

        // Update counts based on current cards in each column
        function updateCounts() {
            boardState.counts = {
                #col-todo: boardState.cards.filter(c => c.id === "#new-card-1").length,
                #col-doing: boardState.cards.filter(c => c.id === "#new-card-2").length,
                #col-done: boardState.cards.filter(c => c.id === "#new-card-3").length
            };
        }

        // Initialize counts from localStorage if available
        function initCounts() {
            const stored = localStorage.getItem('kanban_board_state');
            if (stored) {
                try {
                    updateCounts();
                } catch (e) {
                    console.error("Invalid JSON from localStorage", e);
                }
            }
        }

        // Add a new card to the board
        function addNewCard() {
            const input = document.querySelector('#new-card');
            if (!input.value.trim()) return;

            const text = input.value.trim();
            const btn = input.nextElementSibling;
            const deleteBtn = btn.nextElementSibling;

            // Create card element
            const cardEl = document.createElement('div');
            cardEl.className = 'card';
            cardEl.innerHTML = `
                <span class="card-title">${text}</span>
                <button class="delete-btn" data-id="${btn.id}">Delete</button>
                <button class="add-card-btn" onclick="addNewCard()">Add Card</button>
            `;

            // Add card to board state
            const newCardId = `card-${boardState.cards.length + 1}`;
            boardState.cards.push({
                text: text,
                title: "New Card",
                id: newCardId
            });

            // Move card to appropriate column based on text (simple rule)
            if (text.includes('new')) {
                boardState.columnMap[#col-todo].push(newCardId);
            } else if (text.includes('add')) {
                boardState.columnMap[#col-doing].push(newCardId);
            }

            // Update counts
            updateCounts();

            // Clear input and button
            input.value = '';
            btn.innerHTML = '<button class="delete-btn" data-id="${btn.id}">Delete</button>';
            deleteBtn.textContent = 'Add Card';
        }

        // Delete a card from board state
        function deleteCard(id) {
            boardState.cards = boardState.cards.filter(c => c.id !== id);
            updateCounts();
        }

        // Update counts when cards are added/removed in any column
        function updateCounts() {
            boardState.counts = {
                #col-todo: boardState.cards.filter(c => c.id === "#new-card-1").length,
                #col-doing: boardState.cards.filter(c => c.id === "#new-card-2").length,
                #col-done: boardState.cards.filter(c => c.id === "#new-card-3").length
            };
        }

        // Initialize counts from localStorage if available
        function initCounts() {
            const stored = localStorage.getItem('kanban_board_state');
            if (stored) {
                try {
                    updateCounts();
                } catch (e) {
                    console.error("Invalid JSON from localStorage", e);
                }
            }
        }

        // Initialize counts on page load
        initCounts();

        // Drag-and-drop functionality for cards between columns
        function setupDrag(element, columnId) {
            const container = element.parentElement;

            // Create drop zone
            const dropZone = document.createElement('div');
            dropZone.className = 'drop-zone';
            dropZone.innerHTML = `
                <h4>Drag card to ${columnId}</h4>
                <button class="drag-handler" onclick="moveCard(${element.id}, ${columnId})">Move</button>
            `;

            container.appendChild(dropZone);

            // Attach event listeners for dragstart, dragover, and drop
            element.addEventListener('dragstart', (e) => {
                e.dataTransfer.setData('text/plain', element.id);
                element.classList.add('dragging');
            });

            container.addEventListener('dragover', (e) => {
                e.preventDefault();
                dropZone.style.cursor = 'grabbing';
            });

            container.addEventListener('drop', (e) => {
                const data = e.dataTransfer.getData('text/plain');
                if (data) {
                    moveCard(data, columnId);
                }
            });
        }

        // Move a card from one column to another
        function moveCard(elementId, targetColumnId) {
            const element = document.getElementById(elementId);
            const container = element.parentElement;

            // Find the drop zone for the target column
            const targetDropZone = container.querySelector('.drag-handler');

            if (targetDropZone && !element.classList.contains('dragging')) {
                // Move card to target column
                const newCardId = `card-${boardState.cards.length + 1}`;
                boardState.columnMap[targetColumnId].push(newCardId);

                // Update counts and UI
                updateCounts();

                // Remove from old column (if it exists)
                if (element.parentElement.classList.contains('#col-todo')) {
                    boardState.cards = boardState.cards.filter(c => c.id !== element.id);
                } else if (element.parentElement.classList.contains('#col-doing')) {
                    boardState.cards = boardState.cards.filter(c => c.id !== element.id);
                } else if (element.parentElement.classList.contains('#col-done')) {
                    boardState.cards = boardState.cards.filter(c => c.id !== element.id);
                }

                // Update UI for the card
                const cardEl = document.querySelector(`[data-id="${newCardId}"]`);
                cardEl.textContent = `${element.textContent || ""}`;
            } else {
                // If dragover, move to target column
                if (targetColumnId === '#col-todo') {
                    boardState.columnMap[#col-doing].push(element.id);
                } else if (targetColumnId === '#col-done') {
                    boardState.columnMap[#col-doing].push(element.id);
                }
            }

            // Update UI for the card
            const cardEl = document.querySelector(`[data-id="${element.id}"]`);
            cardEl.textContent = `${element.textContent || ""}`;
        }

        // Initialize drag handlers for each column's cards
        function initDragHandlers() {
            const todoCards = boardState.columnMap[#col-todo];
            if (todoCards.length > 0) {
                todoCards.forEach(cardId => {
                    setupDrag(`card-${cardId}`, #col-todo);
                });
            }

            const doingCards = boardState.columnMap[#col-doing];
            if (doingCards.length > 0) {
                doingCards.forEach(cardId => {
                    setupDrag(`card-${cardId}`, #col-doing);
                });
            }

            const doneCards = boardState.columnMap[#col-done];
            if (doneCards.length > 0) {
                doneCards.forEach(cardId => {
                    setupDrag(`card-${cardId}`, #col-done);
                });
            }
        }

        // Event listeners for buttons to add new cards
        document.querySelectorAll('.add-card-btn').forEach(btn => {
            btn.addEventListener('click', addNewCard);
        });

        // Initialize drag handlers on page load
        initDragHandlers();
    </script>
</body>
</html>
